<script>
export default {
  name: "OptionsGlasses",
  methods: {
  deleteClass() {
    let c = document.getElementById('glasses').children, i;
    for (i = 0; i < c.length; i++) {
      c[i].classList.remove('show');
    }
  },
  showGlasses() {
    if(document.querySelector('#g_glasses').classList.contains('show')) {
      this.deleteClass();
    } else {
      this.deleteClass();
      document.querySelector('#g_glasses').classList.add('show');
    }
  },
  showDWIShades() {
    if(document.querySelector('#g_dwishades').classList.contains('show')) {
      this.deleteClass();
    } else {
      this.deleteClass();
      document.querySelector('#g_dwishades').classList.add('show');
    }
  },
  showOld() {
    if(document.querySelector('#g_old').classList.contains('show')) {
      this.deleteClass();
    } else {
      this.deleteClass();
      document.querySelector('#g_old').classList.add('show');
    }
  },
  showNerd() {
    if(document.querySelector('#g_nerd').classList.contains('show')) {
      this.deleteClass();
    } else {
      this.deleteClass();
      document.querySelector('#g_nerd').classList.add('show');
    }
  },
  showgFancy2() {
    if(document.querySelector('#g_fancy2').classList.contains('show')) {
      this.deleteClass();
    } else {
      this.deleteClass();
      document.querySelector('#g_fancy2').classList.add('show');
    }
  },
  showgHarry() {
    if(document.querySelector('#g_harry').classList.contains('show')) {
      this.deleteClass();
    } else {
      this.deleteClass();
      document.querySelector('#g_harry').classList.add('show');
    }
  }
 }
}
</script>
